@@ -639,6 +640,24 @@ void PruningFunctionCloner::CloneBlock(
         VMap[OldTI] = NewBI;
         ToClone.push_back(Dest);
         TerminatorDone = true;
+      } else {
+        auto *CI = dyn_cast<CmpInst>(BI->getCondition());
+        if (CI && CI->isEquality() &&
+            isa<ConstantPointerNull>(CI->getOperand(1))) {
+          auto *A = dyn_cast<Argument>(CI->getOperand(0));
+          if (A) {
+            bool IsNonNull = CB.paramHasAttr(A->getArgNo(), Attribute::NonNull);
+            if (IsNonNull) {
+              bool IsEqual = CI->getPredicate() == CmpInst::ICMP_EQ;
+              BasicBlock *Dest = BI->getSuccessor(IsEqual);
+              auto *NewBI = BranchInst::Create(Dest, NewBB);
+              NewBI->setDebugLoc(BI->getDebugLoc());
+              VMap[OldTI] = NewBI;
+              ToClone.push_back(Dest);
+              TerminatorDone = true;
+            }
+          }
+        }
       }
     }
   } else if (const SwitchInst *SI = dyn_cast<SwitchInst>(OldTI)) {
@@ -699,13 +718,11 @@ void PruningFunctionCloner::CloneBlock(
 /// This works like CloneAndPruneFunctionInto, except that it does not clone the
